import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}

const ip = "interview_preparation";
const ws = "workplace_scenarios";
const ct = "clinical_transition";
const pd = "professional_development";
const cn = "career_navigation";

export const bulkGeneratedBatch1: ScenarioQuestion[] = [
  q("sq-bg1-1",ip,"behavioral","You are asked about your experience with patient falls.","How have you contributed to fall prevention?","During clinical rotations, I consistently performed fall risk assessments using the Morse Fall Scale, implemented tailored interventions based on risk factors, and educated patients and families about fall prevention. I reported all near-falls and participated in root cause analysis. My commitment to fall prevention demonstrates my understanding that it requires a systematic, team-based approach.","Systematic fall prevention approach.","beginner"),
  q("sq-bg1-2",ip,"behavioral","A colleague asks you to cover their shift last minute.","How do you handle last-minute coverage requests?","I would assess my ability to work safely—am I rested enough? Do I have other commitments? If I can safely cover, I would help my team. If I cannot, I would decline without guilt: 'I wish I could help, but I am not able to today. I hope you find coverage.' Saying no when necessary protects patient safety.","Safe decision-making about additional shifts.","beginner"),
  q("sq-bg1-3",ip,"behavioral","You are asked about how you handle monotonous tasks.","How do you stay engaged during repetitive nursing tasks?","I remind myself that every vital sign check, medication pass, and assessment is an opportunity to catch a change in condition. Repetitive tasks in nursing are never truly routine because the patient is always different. I use checklists to maintain accuracy and take each task as seriously as if it were the first time, because for each patient, their care is not routine—it is personal.","Finding meaning in routine clinical activities.","beginner"),
  q("sq-bg1-4",ip,"clinical_judgment","A patient on warfarin develops a nosebleed that will not stop after 20 minutes of pressure.","How would you manage persistent epistaxis in an anticoagulated patient?","I would continue applying pressure with the patient sitting upright and leaning forward. I would check the INR, assess for other bleeding signs, and notify the provider. If the bleeding does not stop with continued pressure, I would anticipate nasal packing and possible ENT consultation. I would monitor vital signs for hemodynamic compromise and ensure a type and screen is available.","Managing bleeding complications of anticoagulation.","intermediate"),
  q("sq-bg1-5",ip,"clinical_judgment","A patient's chest tube drainage suddenly increases from 50 mL/hr to 300 mL/hr.","What does sudden increased chest tube output indicate?","A sudden increase in chest tube drainage to 300 mL/hr suggests active hemorrhage and is a surgical emergency. I would notify the surgeon immediately, assess vital signs for hypovolemic shock, prepare for blood transfusion, and monitor the drainage closely. Output greater than 200 mL/hr for 2-3 consecutive hours typically requires surgical re-exploration.","Hemorrhage recognition through chest tube output monitoring.","advanced"),
  q("sq-bg1-6",ip,"clinical_judgment","A diabetic patient complains of seeing 'floaters' and has blurred vision.","What does new-onset visual disturbance suggest in a diabetic?","New visual disturbances in a diabetic—floaters and blurred vision—may indicate diabetic retinopathy or vitreous hemorrhage. I would assess blood glucose, check visual acuity if possible, and notify the provider for urgent ophthalmology referral. I would educate the patient about the importance of regular eye exams and tight glucose control. Visual changes can progress to blindness if untreated.","Diabetic eye complications requiring urgent referral.","intermediate"),
  q("sq-bg1-7",ip,"clinical_judgment","A patient with a history of DVT has sudden onset severe headache and papilledema.","What serious condition might this suggest?","Severe headache with papilledema in a patient with DVT history could indicate cerebral venous sinus thrombosis—a blood clot in the brain's venous drainage system. I would perform a neurological assessment, check vital signs, and notify the provider immediately for urgent imaging. This is a neurovascular emergency requiring anticoagulation and possibly interventional radiology.","Cerebral venous thrombosis recognition in DVT-prone patients.","advanced"),
  q("sq-bg1-8",ip,"clinical_judgment","A post-CABG patient develops a new-onset irregular heart rhythm.","What arrhythmia is common after cardiac surgery?","Atrial fibrillation is the most common arrhythmia after CABG, occurring in 25-40% of patients, typically 2-4 days post-operatively. I would assess hemodynamic stability, obtain a 12-lead ECG, check electrolytes (especially potassium and magnesium), and notify the surgeon. I would anticipate orders for rate control medication and possibly amiodarone.","Post-CABG atrial fibrillation recognition and management.","intermediate"),
  q("sq-bg1-9",ip,"scenario_responses","A patient asks to see the hospital chaplain but does not identify with any religion.","How would you support spiritual needs for a non-religious patient?","I would arrange the chaplain visit—hospital chaplains serve all patients regardless of religious affiliation. I would explain: 'Our chaplain provides emotional and spiritual support to everyone. They can listen, help you process what you are going through, and provide comfort without any religious pressure.' I would also offer social work or psychology support as alternatives.","Spiritual support is not limited to religious patients.","beginner"),
  q("sq-bg1-10",ip,"scenario_responses","A patient with limited mobility needs to vote on election day.","How would you help a hospitalized patient exercise their voting rights?","I would research absentee or mail-in ballot options and help the patient access the appropriate resources. I would contact social work or patient advocacy for assistance. I would ensure the patient has access to information and the physical ability to complete a ballot. Supporting patients' civic rights is part of holistic care.","Supporting patient rights beyond medical care.","intermediate"),
  q("sq-bg1-11",ws,"prioritization","You have a patient who needs a blood sugar check at the same time as a blood transfusion reaction check.","How would you prioritize these two time-sensitive checks?","The blood transfusion reaction check takes priority as transfusion reactions can be life-threatening and the 15-minute check is critical for early detection. I would assess the transfusion patient first, then immediately check the blood sugar. If both are truly simultaneous, I would ask a colleague to check one while I check the other.","Life-threatening assessment priority over metabolic monitoring.","beginner"),
  q("sq-bg1-12",ws,"prioritization","Your patient is returning from surgery at the same time as another patient is being discharged.","How would you prioritize post-op recovery versus discharge?","The post-operative patient takes priority because they need immediate post-anesthesia assessment, vital signs, pain management, and monitoring for surgical complications. Discharge, while time-sensitive, can be safely delayed by 30-60 minutes. I would delegate discharge teaching preparation to support staff and focus on the post-op assessment first.","Post-surgical assessment over administrative discharge tasks.","beginner"),
  q("sq-bg1-13",ws,"delegation","You need to delegate ostomy care to an LPN who is certified but has not done it recently.","How would you ensure safe delegation of a skill not recently practiced?","I would ask the LPN to verbalize the ostomy care procedure, offer to observe the first time, and provide current resources for review. I would check in after the care is completed to verify patient tolerance and documentation. Even certified staff may need refresher support for infrequently performed skills.","Competency reassessment for infrequently used skills.","intermediate"),
  q("sq-bg1-14",ws,"delegation","You delegate vital signs and the CNA reports a blood pressure of 70/40 on a previously stable patient.","How would you respond to a critically abnormal vital sign reported by CNA?","I would immediately go to the patient to verify the reading and assess the patient. I would check it myself with a manual cuff. If confirmed, I would assess for signs of shock, lower the head of bed, start rapid IV fluids if ordered, and notify the provider immediately. I would thank the CNA for the prompt report and ensure continuous monitoring.","Immediate verification and emergency response for critical vital signs.","intermediate"),
  q("sq-bg1-15",ws,"patient_safety","A patient's family brings in a space heater for the patient's room.","How would you handle unauthorized electrical equipment in a patient room?","I would explain that personal electrical equipment must be inspected by biomedical engineering before use in the hospital to prevent fire and electrical hazards. I would offer alternatives: additional blankets, adjusting the room temperature, or warm socks. I would follow facility policy and document the interaction.","Fire and electrical safety in patient rooms.","beginner"),
  q("sq-bg1-16",ws,"patient_safety","You notice a staff member not performing hand hygiene before patient contact.","How would you address a hand hygiene violation you witness?","I would address it promptly but respectfully: 'Hey, did you get a chance to sanitize?' Most people appreciate a gentle reminder. If the behavior is habitual, I would report it through the hand hygiene monitoring system or to the charge nurse. Hand hygiene compliance is the single most effective infection prevention measure, and peer accountability is essential.","Peer accountability for infection prevention.","beginner"),
  q("sq-bg1-17",ws,"patient_safety","A patient with a cognitive impairment is refusing necessary medical treatment.","How would you assess capacity to refuse treatment?","I would assess the patient's ability to understand the information being provided, appreciate how it applies to their situation, reason about the risks and benefits, and communicate a consistent choice. If capacity is questionable, I would request a formal capacity evaluation. I would document my assessment findings and ensure the patient's rights are protected regardless of cognitive status.","Capacity assessment framework for treatment refusal.","advanced"),
  q("sq-bg1-18",ws,"medication_error","A nurse from the previous shift documented giving a medication but the medication count shows it was not removed from the dispensing system.","How would you investigate a medication count discrepancy?","I would check the dispensing system log for the specific medication and time. I would review the MAR and patient assessment for evidence the medication was or was not given. I would contact the previous nurse for clarification. If the medication is a controlled substance, this is especially serious and requires immediate pharmacy and management notification. I would file an incident report.","Systematic investigation of medication documentation discrepancies.","intermediate"),
  q("sq-bg1-19",ws,"medication_error","A patient tells you their morning medications taste different than usual.","How would you respond to a patient reporting medications taste different?","I would take this seriously—a taste change could indicate a wrong medication, wrong dose, or a different manufacturer. I would verify each medication against the order, check the NDC number, and contact the pharmacist if anything seems different. I would not dismiss the patient's observation. Patients who take daily medications are often accurate in detecting changes.","Trusting patient medication observations.","beginner"),
  q("sq-bg1-20",ws,"handoff_communication","You need to handoff a patient who has multiple pending tests and consults.","How would you organize handoff for a patient with many pending items?","I would create a clear list of all pending items: labs awaiting results, imaging scheduled, consults requested but not yet seen, and follow-up actions needed. I would prioritize them by urgency and indicate which ones the oncoming nurse needs to follow up on actively versus passively monitor. I would highlight time-sensitive items at the top.","Organized pending-item communication during handoff.","intermediate"),
  q("sq-bg1-21",ws,"difficult_coworkers","A colleague disagrees with you about a patient's care plan in front of the patient.","How would you handle a public disagreement about patient care?","I would calmly redirect: 'Let us step outside to discuss this and then come back with a plan for you.' I would discuss our differing views privately, consult the evidence or a supervisor if needed, and return to the patient with a unified message. Patients should not witness clinical disagreements as it erodes trust in their care team.","Moving disagreements out of patient earshot.","intermediate"),
  q("sq-bg1-22",ws,"interdisciplinary_communication","The case manager is pushing for discharge but PT has not cleared the patient.","How would you advocate for therapy clearance before discharge?","I would communicate the PT's pending assessment to the case manager: 'PT has not yet completed their evaluation. The patient demonstrated instability during our assessment, and I am concerned about safe discharge without PT clearance. Can we delay the discharge pending their assessment?' I would document my concerns and advocacy.","Advocating for complete assessments before discharge.","intermediate"),
  q("sq-bg1-23",ct,"first_shift","A family member asks you a question about a medication you are unfamiliar with.","How would you handle medication questions you cannot answer?","I would be honest: 'That is a great question. I want to make sure I give you accurate information, so let me look it up and get back to you shortly.' I would use the pharmacy reference, drug database, or call the pharmacist. I would never guess or provide inaccurate medication information. Following up promptly builds trust.","Honest acknowledgment with prompt follow-through.","beginner"),
  q("sq-bg1-24",ct,"first_shift","You need to insert a Foley catheter for the first time independently.","How would you prepare for your first independent catheter insertion?","I would review the procedure step by step, gather all supplies including a backup kit, explain the procedure to the patient, maintain strict sterile technique, and visualize each step before performing it. If I have difficulty, I would stop and ask for help rather than compromising sterility. Documenting the catheter size, balloon inflation, and initial output completes the procedure.","Thorough preparation and willingness to ask for help if needed.","beginner"),
  q("sq-bg1-25",ct,"new_nurse_anxiety","A patient deteriorates despite your best care and you feel responsible.","How would you cope with a patient's deterioration?","I would objectively evaluate whether I did everything appropriately: were my assessments thorough, did I communicate changes promptly, did I follow the care plan? If I did my job well, the deterioration reflects the patient's disease process, not my nursing care. I would debrief with my preceptor and seek emotional support. Not every patient improves despite excellent care.","Separating care quality from patient outcomes.","intermediate"),
  q("sq-bg1-26",ct,"time_management","You keep getting behind because you spend too much time in one patient's room.","How would you manage time when patients have extensive needs?","I would set a mental time limit for each room visit and prioritize the most important tasks for each interaction. I would cluster activities to accomplish multiple things per visit. For patients with extensive psychosocial needs, I would schedule dedicated time and set expectations: 'I have 15 minutes right now, and I will come back at 2 PM for a longer conversation.'","Intentional time allocation with scheduled dedicated interactions.","beginner"),
  q("sq-bg1-27",ct,"documentation_challenges","You cannot remember a specific detail you need to document and it happened 4 hours ago.","How would you handle documentation of something you cannot clearly recall?","I would document what I can recall with certainty and note the approximate time. I would not fabricate or guess at details I cannot remember. I would add a note indicating approximation where needed: 'Patient repositioned at approximately 1000.' Going forward, I would develop the habit of documenting immediately after interventions to prevent recall gaps.","Document only what you are certain about with honesty about approximations.","beginner"),
  q("sq-bg1-28",ct,"critical_thinking_drills","A patient's calcium level is 12.5 mg/dL.","What are the implications of hypercalcemia?","A calcium of 12.5 (normal 8.5-10.5) indicates hypercalcemia, which can cause confusion, constipation, polyuria, and cardiac arrhythmias. Common causes include hyperparathyroidism, malignancy, and prolonged immobility. I would ensure IV hydration, place the patient on cardiac monitoring, assess neurological status, and notify the provider. I would anticipate orders for calcitonin, bisphosphonates, and further workup for the cause.","Hypercalcemia recognition with systematic assessment and treatment anticipation.","intermediate"),
  q("sq-bg1-29",ct,"critical_thinking_drills","A patient has a hemoglobin A1C of 10%.","What does a hemoglobin A1C of 10% tell you?","A hemoglobin A1C of 10% indicates poor blood glucose control over the past 2-3 months (target is generally <7% for most diabetics). This correlates with an average blood glucose of about 240 mg/dL. I would assess the patient's diabetes management: medication compliance, dietary habits, access to supplies, and understanding of their disease. I would involve the diabetes educator and provider for regimen adjustment.","HbA1c interpretation and comprehensive diabetes care assessment.","intermediate"),
  q("sq-bg1-30",ct,"critical_thinking_drills","A patient on a clear liquid diet is NPO after midnight for surgery but sneaks breakfast at 6 AM.","How would you handle an NPO violation before surgery?","I would immediately notify the surgeon and anesthesiologist about the NPO violation. The surgery will likely need to be postponed due to aspiration risk during anesthesia. I would document what the patient ate and when. I would educate the patient about the aspiration risk and why NPO instructions are critical. I would not scold but would ensure understanding for any future procedures.","NPO violation management with aspiration risk education.","beginner"),
  q("sq-bg1-31",pd,"professional_boundaries","A patient's family member asks you to accept a tip for your excellent care.","How would you decline a cash tip from a patient's family?","I would decline warmly: 'Thank you so much, but I cannot accept tips or cash gifts. Providing excellent care is what I am here to do. If you want to express your appreciation, a letter to our unit or a donation to the hospital foundation would be wonderful. Your kind words mean more to me than any gift.'","Warm tip decline with alternative appreciation channels.","beginner"),
  q("sq-bg1-32",pd,"ethical_dilemmas","You are caring for a prisoner who is shackled to the bed.","How would you provide ethical care to an incarcerated patient?","I would provide the same quality of care regardless of the patient's legal status. I would maintain their dignity, ensure privacy during examinations (requesting guards to step out when safe), advocate for adequate pain management, and follow the same clinical standards as for any patient. I would address any security measures that interfere with safe medical care.","Equitable care regardless of incarceration status.","intermediate"),
  q("sq-bg1-33",pd,"ethical_dilemmas","A competent adult patient refuses a life-saving blood transfusion based on religious beliefs.","How would you honor a patient's religious refusal of treatment?","I would ensure the patient fully understands the consequences of refusing the transfusion. I would document their informed refusal thoroughly. I would respect their decision while providing all other possible supportive care. I would notify the physician and explore alternative treatments. I would not try to persuade them against their beliefs, but I would ensure true informed decision-making.","Respecting autonomy in faith-based treatment refusal.","advanced"),
  q("sq-bg1-34",pd,"workplace_bullying","You notice a pattern of new nurses being treated differently than established nurses.","How would you address systemic mistreatment of new nurses?","I would document specific patterns of differential treatment. I would bring it up at a unit meeting or discuss it with the nurse educator and manager. I would suggest mentoring programs or buddy systems that pair new and experienced nurses. I would advocate for a positive onboarding culture and recommend anti-bullying training if needed.","Systemic advocacy for new nurse support.","intermediate"),
  q("sq-bg1-35",pd,"advocacy","You observe that patients from lower socioeconomic backgrounds receive less education before discharge.","How would you address health education disparities?","I would ensure my own practice provides equitable education to all patients. I would use health literacy assessment tools and adapt my teaching accordingly. I would bring the disparity to the attention of the quality improvement team with data if possible. I would advocate for standardized discharge education protocols that ensure every patient receives the same baseline of information regardless of their background.","Equitable education through standardized protocols and self-awareness.","intermediate"),
  q("sq-bg1-36",pd,"patient_communication","A patient recently diagnosed with cancer asks: 'Why is this happening to me?'","How would you respond to a patient questioning why they are ill?","I would recognize this as an existential question, not a clinical one. I would sit with them and listen. I would validate their feelings: 'It is natural to wonder why. This is not something you caused or deserve.' I would offer resources: chaplain, counselor, or cancer support groups. I would be present without trying to provide answers that do not exist. Sometimes being heard is what matters most.","Therapeutic presence for existential distress.","intermediate"),
  q("sq-bg1-37",pd,"patient_communication","A caregiver is showing signs of exhaustion and burnout.","How would you support a caregiver who is burning out?","I would validate their experience: 'I can see how much you do for your loved one, and I want to make sure you are also taking care of yourself.' I would provide information about respite care, caregiver support groups, and community resources. I would involve social work. I would remind them that taking care of themselves is not selfish—it is necessary for sustainable caregiving.","Caregiver support and resource connection.","beginner"),
  q("sq-bg1-38",cn,"job_offer_negotiation","You want to negotiate continuing education benefits as part of your compensation.","How would you negotiate for CE benefits?","I would frame it as a win-win: 'Investing in my continuing education will make me a more skilled nurse, which benefits patient care and the organization. I would like to discuss CE reimbursement, study time, and conference attendance as part of my compensation package.' Specific requests for CE hours, tuition reimbursement amounts, and conference attendance show preparation and commitment to growth.","CE benefits as mutual investment framing.","beginner"),
  q("sq-bg1-39",cn,"probation_period","You want to build a strong relationship with your charge nurse during probation.","How would you build rapport with the charge nurse?","I would be reliable, ask appropriate questions, and show initiative. I would communicate my whereabouts, seek feedback proactively, and offer to help when I have downtime. I would not gossip or complain. Building trust with the charge nurse requires consistent demonstration of competence, professionalism, and team orientation.","Building trust through consistent professional behavior.","beginner"),
  q("sq-bg1-40",cn,"performance_evaluation","You want to use your evaluation to request a certification study course.","How would you request professional development resources?","I would tie the request to my evaluation goals: 'In our evaluation, we discussed improving my critical care skills. I have identified a CCRN review course that would support this goal. Would the facility be willing to support my attendance through tuition reimbursement or scheduling accommodation?' Connecting the request to evaluation-identified goals makes it more compelling.","Evaluation-aligned professional development requests.","beginner"),
  q("sq-bg1-41",cn,"career_advancement","You are interested in nursing policy and healthcare advocacy.","How would you get involved in nursing policy?","I would join my state nursing association, which often has policy advocacy committees. I would attend legislative days and learn about current healthcare policy issues. I would write to legislators about nursing-relevant legislation. I would participate in professional organizations that advocate for nursing practice issues. Policy engagement is a form of nursing leadership.","Policy advocacy as nursing leadership.","intermediate"),
  q("sq-bg1-42",cn,"career_advancement","You are considering starting a BSN-to-DNP program.","How would you evaluate BSN-to-DNP programs?","I would evaluate: program accreditation, clinical hour requirements and placement support, faculty expertise, program completion rates, flexibility for working nurses, financial aid availability, capstone project requirements, and post-graduation employment rates. I would talk to current students and alumni. I would assess whether the program aligns with my specific career goals—NP, nurse executive, or clinical specialist.","Comprehensive graduate program evaluation criteria.","intermediate"),
  q("sq-bg1-43",ip,"clinical_judgment","A patient on lithium develops coarse tremors, vomiting, and ataxia.","What do these symptoms suggest in a lithium patient?","Coarse tremors (as opposed to fine tremors which are normal), vomiting, and ataxia suggest moderate to severe lithium toxicity (level likely >2.0 mEq/L). I would hold lithium immediately, obtain a stat lithium level, assess renal function, check electrolytes, ensure aggressive IV hydration, and notify the provider. Severe toxicity can cause seizures, coma, and cardiac arrhythmias. Hemodialysis may be needed for severe cases.","Differentiating mild from severe lithium toxicity symptoms.","advanced"),
  q("sq-bg1-44",ip,"clinical_judgment","A patient receiving TPN develops right upper quadrant pain and jaundice.","What complication might TPN cause?","TPN can cause cholestasis and hepatic complications including fatty liver, cholelithiasis, and cholecystitis. Right upper quadrant pain with jaundice suggests biliary complications. I would assess liver function tests, obtain a right upper quadrant ultrasound, notify the provider, and anticipate TPN formula modifications. If possible, transitioning to enteral nutrition reduces hepatobiliary complications.","TPN-related hepatobiliary complications.","advanced"),
  q("sq-bg1-45",ws,"prioritization","A patient is desaturating while you are in the middle of starting an IV on another patient.","How would you handle competing urgent tasks?","I would stop the IV attempt—a desaturating patient takes immediate priority over IV access. I would address the desaturation first: increase oxygen, assess the patient, call for help if needed. I would then return to complete the IV start. Oxygen desaturation is potentially life-threatening and cannot wait.","Life-threatening priorities override procedural tasks.","beginner"),
  q("sq-bg1-46",ws,"patient_safety","A confused patient keeps unplugging their bed alarm.","How would you maintain safety monitoring for a patient defeating safety devices?","I would assess why the patient is removing the alarm and address root causes: discomfort, confusion, or noise sensitivity. I would try alternative alarm types or placements. I would consider a sitter if the patient is high fall risk. I would not simply keep re-applying the same approach that is not working. I would involve the charge nurse and provider in developing an effective safety plan.","Adaptive safety planning when standard measures fail.","intermediate"),
  q("sq-bg1-47",ct,"critical_thinking_drills","A patient has a positive Babinski sign.","What does a positive Babinski sign indicate in an adult?","In adults, a positive Babinski sign (dorsiflexion of the great toe with fanning of other toes when the sole is stroked) is abnormal and indicates upper motor neuron damage. This could suggest stroke, spinal cord injury, brain tumor, or other central nervous system pathology. I would perform a complete neurological assessment and notify the provider for further evaluation.","Abnormal reflex recognition and neurological assessment.","intermediate"),
  q("sq-bg1-48",ct,"critical_thinking_drills","A patient's serum osmolality is 320 mOsm/kg.","What does elevated serum osmolality indicate?","Elevated serum osmolality (normal 275-295) indicates concentrated blood, often from dehydration, hyperglycemia (DKA or HHS), hypernatremia, or uremia. In the context of the patient's clinical picture, I would assess fluid status, check blood glucose and electrolytes, review I&O, and assess for signs of dehydration. I would anticipate IV fluid resuscitation and treatment of the underlying cause.","Serum osmolality interpretation with clinical correlation.","advanced"),
  q("sq-bg1-49",pd,"ethical_dilemmas","A patient who is a healthcare worker tells you to chart something differently because they know how the system works.","How would you respond to a healthcare-savvy patient manipulating documentation?","I would explain that my documentation must reflect my actual findings and interventions accurately regardless of their healthcare knowledge. I would say, 'I understand you are familiar with how charting works, but I need to document what I observe and do. Is there a specific concern about the documentation I can address?' I would not alter documentation to satisfy a patient's request.","Documentation integrity despite patient pressure.","intermediate"),
  q("sq-bg1-50",pd,"advocacy","A patient's treatment is being delayed because of an insurance pre-authorization requirement.","How would you address treatment delays from insurance requirements?","I would involve the case manager immediately to expedite the pre-authorization. I would ensure the physician provides the clinical justification needed. I would document the delay and its impact on the patient's care. I would keep the patient informed about the process. For urgent treatments, many facilities have emergency authorization pathways that should be explored.","Expediting insurance barriers for timely treatment.","intermediate"),
  q("sq-bg1-51",ws,"medication_error","You notice that a high-alert medication does not have the required independent double-check documented.","How would you handle a missing independent double-check for a high-alert medication?","I would stop and perform the independent double-check now, even if the medication has already been started. I would verify the medication, dose, concentration, pump rate, and patient identification with another nurse. I would document the verification and discuss the importance of the double-check protocol with the administering nurse. Missing this step for high-alert medications is a serious safety gap.","Retroactive safety verification for high-alert medications.","intermediate"),
  q("sq-bg1-52",ct,"documentation_challenges","You need to document a patient's refusal to comply with isolation precautions.","How would you document a patient's non-compliance with isolation?","I would document objectively: the isolation precautions ordered, what the patient was doing that violated precautions, the education I provided about the reasons for isolation, the patient's response to education, and the provider's awareness. I would not use judgmental language like 'patient refuses to cooperate.' Instead: 'Patient educated about contact isolation requirements; patient verbalized understanding but declined to remain in room.'","Objective documentation of isolation non-compliance.","intermediate"),
  q("sq-bg1-53",cn,"career_advancement","You are considering becoming a certified diabetes educator.","How would you pursue diabetes education certification?","I would accumulate the required 2,000 hours of diabetes education experience, study for the Certified Diabetes Care and Education Specialist (CDCES) exam, and build expertise in insulin management, CGM technology, nutrition counseling, and behavior change techniques. I would network with current CDCESs and join the Association of Diabetes Care and Education Specialists.","Specific pathway to diabetes education certification.","intermediate"),
  q("sq-bg1-54",ip,"scenario_responses","A patient wants to use their own essential oils in the hospital room.","How would you address a patient wanting to use essential oils?","I would check facility policy on aromatherapy and essential oil use. I would explain potential concerns: allergies of neighboring patients, interactions with medications, and oil residue on equipment. If policy permits, I would work with the patient on safe use. If not, I would explain the restriction and offer alternatives for comfort like music or guided imagery.","Policy-based approach with patient comfort alternatives.","beginner"),
  q("sq-bg1-55",ws,"handoff_communication","You are leaving and notice a new order was placed in the last 10 minutes of your shift.","How would you handle a last-minute order at shift change?","I would review the order to assess urgency. If it requires immediate action, I would begin implementing it and include it in my handoff. If it can be deferred to the next shift, I would highlight it prominently in my handoff: 'A new order was placed at 1850—here are the details.' I would not ignore it because my shift is ending. I would document my awareness and communication of the order.","Responsible handling of late-shift orders.","beginner"),
  q("sq-bg1-56",ct,"new_nurse_anxiety","You are assigned to a patient population you are unfamiliar with.","How would you prepare for an unfamiliar patient population?","I would spend time before my shift reviewing common conditions, treatments, and nursing considerations for that patient population. I would ask my charge nurse or preceptor about the most important things to know. I would identify resources available on the unit. I would be extra vigilant in my assessments and ask questions freely. Every unfamiliar assignment is a learning opportunity.","Pre-shift preparation for unfamiliar clinical areas.","beginner"),
  q("sq-bg1-57",pd,"patient_communication","You need to explain informed consent to a patient before a procedure.","How would you ensure a patient truly understands informed consent?","I would ensure the physician has explained the procedure, risks, benefits, and alternatives. I would verify understanding using teach-back: 'In your own words, can you tell me what the doctor is going to do and what the risks are?' I would answer questions within my scope and get the physician if the patient has clinical questions. I would ensure the patient knows they can withdraw consent at any time.","Teach-back for genuine informed consent verification.","beginner"),
  q("sq-bg1-58",cn,"probation_period","Your orientation is moving faster than you are comfortable with.","How would you communicate that orientation pace is too fast?","I would speak up to my preceptor and nurse educator: 'I want to be transparent that I feel the orientation is moving faster than I can safely absorb. I would rather take a little more time now than be released to independent practice before I am truly ready. Can we slow down on [specific areas]?' Advocating for adequate preparation is professional responsibility, not weakness.","Self-advocacy for safe orientation pacing.","beginner"),
  q("sq-bg1-59",ip,"behavioral","Tell me about your experience with infection control.","How do you practice infection prevention?","Infection prevention is integrated into everything I do: proper hand hygiene before and after every patient contact, correct PPE use, sterile technique for invasive procedures, and adherence to isolation protocols. I also educate patients and families about infection prevention. During clinical, I participated in our unit's hand hygiene monitoring and helped achieve a compliance rate above 95%.","Comprehensive infection prevention integrated into daily practice.","beginner"),
  q("sq-bg1-60",ws,"difficult_coworkers","A colleague makes cultural insensitivity comments about patients.","How would you address cultural insensitivity from a colleague?","I would address it privately and directly: 'I heard you say [specific comment] about our patient. Those kinds of comments do not reflect our professional values and could affect the care we provide. All our patients deserve respectful treatment regardless of their background.' If the behavior continued, I would escalate to management. Cultural insensitivity can constitute a hostile work environment.","Direct address of cultural insensitivity with escalation if needed.","intermediate"),
  q("sq-bg1-61",ip,"clinical_judgment","A patient with known aortic aneurysm develops sudden severe back pain radiating to the abdomen.","What emergency might this suggest?","Sudden severe back pain radiating to the abdomen in a patient with a known aortic aneurysm suggests possible aneurysm rupture or dissection—a life-threatening emergency. I would call for help immediately, assess vital signs for hemodynamic collapse, establish large-bore IV access, prepare for emergent blood products, and notify the vascular surgeon STAT. Time to surgery is critical for survival.","Aortic emergency recognition with immediate surgical notification.","advanced"),
  q("sq-bg1-62",ct,"time_management","You have documentation to complete but your patient needs emotional support.","How would you balance documentation with emotional care?","I would provide emotional support first—this is nursing, not just task completion. I would sit with the patient for a focused amount of time, address their emotional needs, and then document afterward. I could also chart at the bedside while being present with the patient. Emotional care is not optional—it is core nursing and affects patient outcomes.","Emotional care prioritization with creative documentation timing.","beginner"),
  q("sq-bg1-63",pd,"ethical_dilemmas","A patient asks you not to document that they admitted to using illegal drugs.","How would you handle a request to omit drug use from documentation?","I would explain that accurate documentation is essential for their safety: 'I understand your concern about privacy. The reason I need to document this is to protect you—certain medications and anesthesia can interact with substances, and your care team needs to know to keep you safe. Your medical records are confidential and protected by law.' I would not omit clinically relevant information.","Patient safety rationale for complete documentation.","intermediate"),
  q("sq-bg1-64",cn,"career_advancement","You want to develop expertise in evidence-based practice.","How would you become an EBP champion on your unit?","I would start by identifying clinical questions from my practice and searching for evidence-based answers. I would learn to critically appraise research articles. I would join or start a journal club. I would propose small EBP projects on my unit. I would pursue training in EBP methodology. Being an EBP champion means being the person colleagues turn to when they want to know 'what does the evidence say?'","Practical EBP champion development.","intermediate"),
  q("sq-bg1-65",ws,"interdisciplinary_communication","A consultant's recommendations conflict with the hospitalist's plan, and both are valid approaches.","How would you facilitate resolution between conflicting valid approaches?","I would communicate the conflict to both providers: 'I want to make sure we have a unified plan. The consultant recommended X while the hospitalist ordered Y. Both approaches have merit. Could you communicate with each other to determine the best approach for this patient?' I would document my communication and ensure the patient receives clear, consistent messaging about their care plan.","Facilitating provider-to-provider communication for plan consistency.","intermediate"),
  q("sq-bg1-66",ip,"behavioral","Describe a time when you had to say no to a request.","How do you set professional limits while maintaining relationships?","A colleague asked me to switch shifts at the last minute for the third week in a row. I said no clearly but kindly: 'I value our working relationship, and I have helped when I could. However, I need to protect my personal time this week to prevent burnout. I hope you understand.' Setting limits respectfully preserves both the relationship and my wellbeing.","Assertive limit-setting while preserving relationships.","beginner"),
  q("sq-bg1-67",ct,"critical_thinking_drills","A patient's potassium level is 6.2 mEq/L.","What does hyperkalemia at this level require?","A potassium of 6.2 is potentially life-threatening. I would immediately place the patient on cardiac monitoring, assess for ECG changes (peaked T waves, widened QRS, potential cardiac arrest), and notify the provider STAT. I would anticipate orders for: IV calcium gluconate for cardiac protection, insulin with dextrose to shift potassium intracellularly, kayexalate for potassium removal, and possible dialysis if renal failure is present.","Hyperkalemia emergency management.","advanced"),
  q("sq-bg1-68",pd,"workplace_bullying","A colleague makes sarcastic comments about your age or generation.","How would you address age-related comments from colleagues?","I would address it directly: 'I have noticed some comments about my generation/age that make me uncomfortable. I would appreciate being judged on my clinical performance and professionalism rather than my age.' If comments continued, I would document them as they may constitute age-based harassment. Every generation brings valuable perspectives to nursing.","Direct address of age discrimination.","intermediate"),
  q("sq-bg1-69",cn,"performance_evaluation","Your evaluation is perfect but you want to advocate for career advancement.","How would you leverage a perfect evaluation?","I would use the positive evaluation as evidence for my advocacy: 'Thank you for this evaluation. I have demonstrated consistent excellence and am ready for the next challenge. I would like to discuss opportunities for charge nurse training, committee leadership, or specialty development.' I would present a specific development plan rather than a vague request for advancement.","Using positive evaluations as career leverage.","beginner"),
  q("sq-bg1-70",ip,"scenario_responses","A patient is visibly frightened before a procedure.","How would you calm a fearful patient before a procedure?","I would sit with them and acknowledge their fear: 'It is completely normal to feel nervous. Tell me what you are most worried about.' I would address specific concerns, explain what to expect step by step, discuss pain management options, and offer comfort measures like music or deep breathing. I would ensure they know they can ask questions or request a pause at any time. My presence and calm demeanor help reduce anxiety.","Empathetic acknowledgment with specific fear exploration and comfort measures.","beginner"),
  q("sq-bg1-71",ws,"medication_error","A pharmacy technician calls to say they sent the wrong concentration of a medication to your unit.","How would you respond to a pharmacy notification of a wrong medication sent?","I would immediately locate the incorrect medication on the unit, quarantine it so it cannot be administered, and verify whether it has already been given to any patient. If it was administered, I would assess the patient, calculate the dosing impact, and notify the provider. I would document the pharmacy error and ensure the correct medication is sent immediately. I would file an incident report.","Immediate quarantine and exposure assessment for pharmacy errors.","intermediate"),
  q("sq-bg1-72",ct,"first_shift","You encounter your first emergency situation during orientation.","How would you respond to your first emergency as a new nurse?","I would activate emergency protocols—call a code, rapid response, or whatever is appropriate. I would start CPR if needed, apply oxygen, and follow the systematic approach I learned in BLS/ACLS. I would accept whatever role is assigned during the emergency. Afterward, I would debrief with my team, process my emotions, and identify what I did well and what I want to improve for next time.","Following training-based protocols during first emergencies.","intermediate"),
  q("sq-bg1-73",pd,"advocacy","A patient is being discharged to a home environment you believe is unsafe.","How would you advocate against an unsafe home discharge?","I would document specific safety concerns: living conditions, support availability, medication management ability, and functional status. I would involve social work for a home safety assessment, discuss my concerns with the case manager and physician, and explore alternative placement options. I would not discharge a patient to an environment I believe is unsafe without exhausting all advocacy channels.","Comprehensive advocacy with multi-disciplinary involvement.","intermediate"),
  q("sq-bg1-74",cn,"job_offer_negotiation","You receive a job offer with a vague job description.","How would you clarify an unclear job description before accepting?","I would ask specific questions: 'What does a typical shift look like? What is the nurse-to-patient ratio? What specific skills and competencies does this role require? What is the orientation process? What support is available for new nurses?' A vague job description is a red flag—clarity before acceptance prevents surprises. I would request a written, detailed job description before signing.","Seeking specificity before accepting positions.","intermediate"),
  q("sq-bg1-75",ip,"clinical_judgment","A patient on nitroglycerin develops a severe headache.","Is this an expected side effect and how would you manage it?","Headache is a common and expected side effect of nitroglycerin due to vasodilation. I would administer acetaminophen if ordered for the headache, continue the nitroglycerin as prescribed, monitor blood pressure (nitroglycerin can cause hypotension), and reassure the patient that headache usually improves with continued use. I would notify the provider if the headache is severe or if blood pressure drops significantly.","Expected drug side effect management with monitoring.","beginner"),
  q("sq-bg1-76",ws,"patient_safety","A patient is wearing copper bracelets they believe help their arthritis.","How would you handle complementary therapy items?","I would respect the patient's belief while ensuring safety. Copper bracelets are generally not harmful and do not interfere with medical care. I would check if the bracelet needs to be removed for any procedures or imaging (MRI). I would not dismiss their belief but would provide evidence-based information about arthritis treatment alongside their complementary choices.","Respecting complementary beliefs while ensuring medical safety.","beginner"),
  q("sq-bg1-77",ct,"new_nurse_anxiety","You feel like an imposter when patients call you 'nurse.'","How would you internalize your professional identity?","I would remind myself that I completed rigorous education, passed the NCLEX, and earned my license. I am qualified to be called 'nurse.' Identity formation takes time—I would practice accepting the title, build confidence through clinical success, and find mentors who reinforce my professional identity. Imposter syndrome is common but does not define my competence.","Professional identity development over time.","beginner"),
  q("sq-bg1-78",pd,"patient_communication","You need to discuss code status with a patient and their family.","How would you facilitate a code status conversation?","I would create a comfortable environment, explain what code status means in clear language, present the options (full code, DNR, comfort care) without bias, answer questions honestly, and allow time for discussion. I would ensure the physician has initiated the conversation about prognosis first. I would support whatever decision the patient makes and document the discussion thoroughly.","Supportive, unbiased code status discussion facilitation.","intermediate"),
  q("sq-bg1-79",ws,"delegation","Your entire team is stretched thin and there are not enough tasks that can be delegated.","How would you manage when delegation options are exhausted?","I would communicate with the charge nurse: 'I have delegated everything I appropriately can, and my team and I are still stretched beyond safe capacity. We need additional support.' I would prioritize the most critical tasks, defer non-urgent activities, and document the staffing situation. If patient safety is at risk, I would file an Assignment Despite Objection form and escalate up the chain of command.","Escalation when delegation cannot resolve unsafe workload.","advanced"),
  q("sq-bg1-80",cn,"career_advancement","You are interested in developing your skills in simulation education.","How would you get involved in nursing simulation?","I would volunteer to help with orientation simulations on my unit. I would seek training in simulation facilitation and debriefing techniques. I would develop clinical scenarios based on common unit events. I would pursue certification in healthcare simulation. Simulation is a growing field that combines clinical expertise with education—a natural fit for experienced bedside nurses who want to teach.","Simulation education involvement pathway.","intermediate"),
];
